def apply_action(state: List[List[int]], action: int) -> List[List[int]]:
    """
    Apply the given action to the grid `state`.

    For ACTION2 we only modify the three cells at rows 60‑62,
    column 28, changing their value from 0 to 14.
    All other cells remain unchanged.
    """
    if action == ACTION2:
        for row in (60, 61, 62):
            # ensure the cell currently holds 0 before updating
            if state[row][28] == 0:
                state[row][28] = 14
    return state
